<?php require '../config.php'; require_admin(); require '_nav.php'; $rows=$pdo->query('SELECT b.*,h.db_name,u.name,u.email FROM backups b JOIN hosting_accounts h ON h.id=b.hosting_account_id JOIN users u ON u.id=h.user_id ORDER BY b.id DESC')->fetchAll(); ?>
<!doctype html><html><head><title>Backups</title><link rel="stylesheet" href="/style.css"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body><div class="dash"><?php admin_nav(); ?><div class="main"><h1>Backups</h1><table class="table"><tr><th>Customer</th><th>Type</th><th>Path</th><th>Size</th><th>Date</th><th>Action</th></tr><?php foreach($rows as $r):?><tr><td><?=h($r['name'])?><br><small><?=h($r['email'])?></small></td><td><?=h($r['backup_type'])?></td><td><small><?=h($r['file_path'])?></small></td><td><?=h(fmt_bytes($r['file_size']))?></td><td><?=h($r['created_at'])?></td><td><form class="inline" method="post" action="/admin/backup_action.php"><?=csrf_field()?><input type="hidden" name="id" value="<?=h($r['id'])?>"><input type="hidden" name="action" value="restore"><button class="btn small danger" onclick="return confirm('Restore this backup over the current account data?')">Restore</button></form></td></tr><?php endforeach;?></table></div></div></body></html>
